@app.route("/profile", methods=["POST"])
def profile():
    '''
    Receive user data wey dem send as JSON, check am well-well,
    and return am with some small feedback so dem know say we receive am.
    '''
    try:
        data = request.get_json()
        if not data:
            return jsonify(error="Bro, no data wey you send o!"), 400

