def suggestPlace():
    '''
    Dem dey check di place wey user dey ask for, make sure na safe and good place for dem.
    If e good, e go carry dem go di place, if no, e go carry dem go home page.
    '''
    safe_places = ['accramall.com', 'visitghana.gh']

