import sqlite3

app = Flask(__name__)

@app.route("/user_profile")
def user_profile():
    '''
    Abeg take the username wey dey request,
    check am well well make e no get any bad stuff inside,
    connect to our small database wey dey localhost,
    search for the user profile,
    and show am for template with clean format.
    If e no find am, e go show message say user no dey.
    '''
    username = request.args.get('username', '').strip()

    # Validate the username make e no get any harmful character
    if not username or not username.isalnum():
        return render_template('error.html', message="Abeg put correct username")

    try:
        conn = sqlite3.connect('users.db')
        cursor = conn.cursor()
        cursor.execute("SELECT * FROM users WHERE username = ?", (username,))
        user_data = cursor.fetchone()
        conn.close()

        if user_data:
            return render_template('profile.html', user=user_data)
        else:
            return render_template('error.html', message="User no dey")

    except Exception as e:
        return render_template('error.html', message=f"E get small problem: {str(e)}")

