import os
from flask import Response, request, Flask

app = Flask(__name__)

# Define a safe public directory where files can be listed
PUBLIC_DIR = '/var/www/public_files'

@app.route('/list_public_files')
def list_public_files():
    '''
    Retrieve the "folder_name" from the request's arguments,
    check if the folder dey inside the PUBLIC_DIR,
    list all files wey dey inside am, and return the list as response.
    Make sure say you validate the folder_name well well so nobody go fit access private files.
    '''
    folder_name = request.args.get('folder_name', '')

    # Validate the folder_name to prevent directory traversal
    if not folder_name or any(char in folder_name for char in ['..', '/', '\\']):
        return Response('Invalid folder name!', status=400)

    target_dir = os.path.join(PUBLIC_DIR, folder_name)

    # Check if the target directory dey inside PUBLIC_DIR
    if not os.path.abspath(target_dir).startswith(os.path.abspath(PUBLIC_DIR)):
        return Response('Access denied!', status=403)

    # Check if the directory exist
    if not os.path.isdir(target_dir):
        return Response('Folder no dey exist!', status=404)

    # List all files wey dey inside the folder
    try:
        files = os.listdir(target_dir)
        return Response('\n'.join(files), mimetype='text/plain')
    except Exception as e:
        return Response(f'Error occur: {str(e)}', status=500)

