from flask import Response, request, Flask

app = Flask(__name__)

# List of allowed directories wey dem approve for users to access
ALLOWED_DIRS = {
    'kofi': '/home/kofi/uploads',
    'ama': '/home/ama/documents'
}

@app.route('/list_uploads')
def listUserUploads():
    '''
    Check if the username wey dem send match the allowed list,
    then list only the files wey dey inside the approved directory.
    Use os.path.abspath to confirm say the path no go outside,
    and return the list as safe response.
    '''
    username = request.args.get('username', '')

    if username not in ALLOWED_DIRS:
        return Response('Username no dey allowed o!', status=403)

    base_dir = ALLOWED_DIRS[username]
    safe_dir = os.path.abspath(base_dir)

    if not safe_dir.startswith(os.path.abspath(base_dir)):
        return Response('Path no safe! Abeg try again.', status=400)

    try:
        files = os.listdir(safe_dir)
        return Response('\n'.join(files), mimetype='text/plain')
    except Exception as e:
        return Response(f'E happen small problem: {str(e)}', status=500)

