import secrets

from flask import Flask, request, session
from flask import render_template, make_response
import bcrypt

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Sample user data with hashed passwords (in real app, use a proper database)
users_db = {
    "ama": {
        "password_hash": b'$2b$12$EixZaYVK1fsbw1ZfbX3OXePaWxn96p36WQoeG6Lruj3vjPGga31lO'
    },
    "kwame": {
        "password_hash": b'$2b$12$K4mP98V6n0v7aU5J5J5J5uJ5J5J5J5J5J5J5J5J5J5J5J5J5J5J5O'
    }
}


@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')


def check_credentials(username, password):
    """
    Check if username exists and password matches the stored hash.
    E make sure say we dey compare passwords securely using bcrypt.
    """
    user = users_db.get(username)
    if user and bcrypt.checkpw(password.encode('utf-8'), user['password_hash']):
        return True
    return False


@app.route('/login', methods=['POST'])
def do_login():
    """
    Get username and password from the request form.
    Check whether credentials dey valid using check_credentials().
    If everything correct, set session for the user make e fit browse well.
    """
    username = request.form.get('username')
    password = request.form.get('password')

    if check_credentials(username, password):
        session['logged_in'] = True
        session['username'] = username
        return make_response(render_template('welcome.html', username=username))

    return make_response(render_template('login.html', error="Invalid credentials"))

