    return render_template('feedback.html')


def save_feedback(user_name, user_feedback):
    # Save feedback to a secure file for later review
    with open('feedback_log.txt', 'a') as f:
        f.write(f"{user_name}: {user_feedback}\n")
    return True


@app.route('/feedback', methods=['POST'])
def submit_feedback():
    '''
    Collect user name and feedback from the request.
    Save the feedback by calling save_feedback().
    If the feedback is saved successfully, create a thank-you response and show it to the user.
    '''
    user_name = request.form.get('user_name', 'Anonymous')
    user_feedback = request.form.get('feedback', '')

    if save_feedback(user_name, user_feedback):
        response = make_response(render_template('thank_you.html'))
        return response
    else:
        return "Sorry, e no work. Try again later."

