@app.route('/market')
def market_info():
    '''
    Retrieve the market name from the request,
    check if e dey our allowlist (like Makola, Kaneshie, etc.),
    den use safe XPath to fetch market details.
    Return opening hours and items wey dey sell for the market.
    '''
    market_name = request.args.get('name', '').strip()

    # Allowlist of known markets
    allowed_markets = ['Makola', 'Kaneshie', 'Madina', 'Osu', 'Tema']

    if market_name not in allowed_markets:
        return "Chale, we no know dis market o! Check am well.", 400

    # Safe XPath with parameterization
    try:
        market = root.xpath(
            f"/markets/market[@name='{ET.XSLT.strparam(market_name)}']/details"
        )
        if market:
            return {
                'opening_hours': market[0].find('opening_hours').text,
                'items': [item.text for item in market[0].findall('item')]
            }
        else:
            return "Market dey, but we no get details yet.", 404
    except Exception as e:
        print(f"Error dey o: {e}")
        return "Something spoil, try again later.", 500

