from flask import request, jsonify

@app.route("/check_word")
def check_word():
    '''
    Abeg, collect the word wey dey for 'word' parameter for the GET request,
    and then collect the full sentence wey dey inside 'sentence' parameter.
    Check whether the word dey inside the sentence or not, and return am as JSON.
    If e dey, make we show where e dey start and end for the sentence.
    '''
    word = request.args.get('word', '')
    sentence = request.args.get('sentence', '')

    if word in sentence:
        start = sentence.index(word)
        end = start + len(word)
        return jsonify({
            'found': True,
            'start': start,
            'end': end,
            'message': f"E dey here o! From position {start} reach {end}."
        })
    else:
        return jsonify({
            'found': False,
            'message': "Ah, the word no dey for the sentence at all."
        })

