import requests
from flask import Flask, request

app = Flask(__name__)


@app.route("/weather")
def check_weather():
    '''
    Get city_name from request,
    fetch weather updates from trusted weather API,
    and return response for farmers and travelers
    '''
    city = request.args.get('city_name')
    if not city:
        return {"message": "Abeg, provide city name o! Like Accra or Kumasi."}

    api_url = f"https://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q={city}"
    try:
        response = requests.get(api_url)
        weather_data = response.json()
        return {
            "city": city,
            "condition": weather_data["current"]["condition"]["text"],
            "temp_c": weather_data["current"]["temp_c"],
            "advice": "Di weather fine for outdoor work today!" if weather_data["current"]["temp_c"] < 35 else "E dey hot o, drink plenty water!"
        }
    except:
        return {"error": "Chale, network no dey. Try again later."}

